import pika

# RabbitMQ connection parameters
connection = pika.BlockingConnection(pika.ConnectionParameters('localhost', 5672))
channel = connection.channel()

# Declare a queue to send tasks
task_queue_name = 'task_queue'
channel.queue_declare(queue=task_queue_name, durable=True)

# Publisher function to send messages to the task queue
def publish_task(task):
    channel.basic_publish(exchange='',
                          routing_key=task_queue_name,
                          body=task,
                          properties=pika.BasicProperties(
                              delivery_mode=2,  # make message persistent
                          ))
    print(f" [x] Sent {task}")

# Consumer callback function to process messages
def callback(ch, method, properties, body):
    print(f" [x] Received {body}")
    # Simulate task processing time
    import time
    time.sleep(body.count(b'.'))
    print(" [x] Done")
    ch.basic_ack(delivery_tag=method.delivery_tag)

# Consumer function to start listening for messages
def consume_tasks():
    channel.basic_qos(prefetch_count=1)
    channel.basic_consume(queue=task_queue_name,
                          on_message_callback=callback)

    print(' [*] Waiting for tasks. To exit press CTRL+C')
    channel.start_consuming()

if __name__ == '__main__':
    # Example usage: send a task
    publish_task("Hello World...")

    # Start consuming tasks
    consume_tasks()